async (page) => {
  var title = "图解 Blaze · 第 19 章 · 代码到 SQL 全路径追踪 — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 19 章 · 代码到 SQL 全路径追踪</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">CriteriaBuilder → 表达式树 → JPQL → HQL → SQL · 每一步都附真实输出</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\">一行 Java 代码到数据库执行的 SQL，中间到底经过了多少次变换？本章以一条<strong style=\"color:#1a1a2e;font-weight:700;\">真实的聚合查询</strong>为例，追踪它穿越 CriteriaBuilder API、ExpressionFactory、隐式 JOIN 解析、QueryGenerator、Hibernate HQL 解析器直至最终原生 SQL 的每一帧变化。<strong style=\"color:#1a1a2e;font-weight:700;\">每个步骤都同时给出框架状态图和实际的 JPQL / SQL 输出</strong>——图看结构，代码看结果。</p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">观察每个 API 调用后框架内部 Manager 状态的逐帧变化，<strong style=\"color:#1a1a2e;font-weight:700;\">并用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">getQueryString()</code> 验证中间 JPQL</strong></li><li style=\"margin-bottom:4px;font-size:13px;\">理解 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ExpressionFactory</code> 如何将字符串解析为类型化的表达式树，<strong style=\"color:#1a1a2e;font-weight:700;\">并给出解析后的数据结构</strong></li><li style=\"margin-bottom:4px;font-size:13px;\">追踪隐式 JOIN 从路径表达式推导到 JoinNode 树扩展的完整过程，<strong style=\"color:#1a1a2e;font-weight:700;\">对比解析前后的 JPQL 差异</strong></li><li style=\"margin-bottom:4px;font-size:13px;\">看到 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">QueryGenerator</code> 如何遍历所有 Manager 拼接 JPQL，<strong style=\"color:#1a1a2e;font-weight:700;\">展示逐子句的拼接过程</strong></li><li style=\"margin-bottom:4px;font-size:13px;\">跟随 JPQL 进入 Hibernate 内部被翻译为原生 SQL，<strong style=\"color:#1a1a2e;font-weight:700;\">给出完整的 PostgreSQL 输出</strong></li><li style=\"margin-bottom:4px;font-size:13px;\">对比 Entity View 应用后路径差异，<strong style=\"color:#1a1a2e;font-weight:700;\">附完整 View 定义和生成的 JPQL</strong></li></ul><p style=\"font-size:12px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">前置知识：<span style=\"color:#1e6fff;\">第 3 章 · CriteriaBuilder 核心</span> 的 API 使用，以及 <span style=\"color:#1e6fff;\">第 14 章 · 渲染管线</span> 对 QueryGenerator 的初步了解。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">本章追踪的示例查询</strong> — 查询已完成订单中电子产品类别、按客户分组、总额超过 1000 的前 20 名客户：\n</section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .select(\"o.customer.name\")<br/>    .select(\"SUM(o.totalAmount)\")<br/>    .join(\"o.items\", \"i\", JoinType.LEFT)<br/>    .where(\"o.status\").eq(OrderStatus.COMPLETED)<br/>    .where(\"i.product.category\").eq(\"Electronics\")<br/>    .groupBy(\"o.customer.name\")<br/>    .having(\"SUM(o.totalAmount)\").gt(1000)<br/>    .orderByAsc(\"o.customer.name\")<br/>    .setMaxResults(20);</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">下面的实体模型是本章 SQL 追踪的基础：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@Entity @Table(name = \"orders\")<br/>public class Order {<br/>    @Id private Long id;<br/>    @ManyToOne private Customer customer;<br/>    @OneToMany(mappedBy = \"order\") private Set&lt;OrderItem&gt; items;<br/>    @Enumerated(EnumType.STRING) private OrderStatus status;<br/>    @Column(name = \"total_amount\") private BigDecimal totalAmount;<br/>}<br/><br/>@Entity @Table(name = \"customers\")<br/>public class Customer {<br/>    @Id private Long id;<br/>    private String name;<br/>}<br/><br/>@Entity @Table(name = \"order_items\")<br/>public class OrderItem {<br/>    @Id private Long id;<br/>    @ManyToOne private Order order;<br/>    @ManyToOne private Product product;<br/>    private int quantity;<br/>}<br/><br/>@Entity @Table(name = \"products\")<br/>public class Product {<br/>    @Id private Long id;<br/>    private String category;<br/>    private String name;<br/>}</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">19.1 第一步：CriteriaBuilder API 调用 → 内部 Manager 填充</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">每个 CriteriaBuilder 方法调用都会修改内部某个 Manager 的状态。以下逐帧展示从空白到完整的状态变化，<strong style=\"color:#1a1a2e;font-weight:700;\">并在每帧之后调用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">getQueryString()</code> 打印中间 JPQL</strong>。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">帧 ① — <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">cbf.create(em, Tuple.class)</code></h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory.create()</code> 实例化 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">AbstractCommonQueryBuilder</code>，内部初始化所有 Manager 为空。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-1 create() 后 — 所有 Manager 为空</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">AbstractCommonQueryBuilder</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">SelectManager<br/>📋 items: ∅</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">JoinManager<br/>🌳 roots: ∅</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">WhereManager<br/>🔍 rootPredicate: ∅</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">GroupByManager<br/>📊 expressions: ∅</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">HavingManager<br/>⚖️ rootPredicate: ∅</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">OrderByManager<br/>🔢 items: ∅</p></section></td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">帧 ② — <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.from(Order.class, \"o\")</code></h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">JoinManager 收到第一个根节点。此时可以调用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">getQueryString()</code>，但由于没有 SELECT 子句，查询仅有 FROM：</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-2 from() 后 — JoinManager 获得根 JoinNode</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JoinManager</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JoinNode<br/>type: Order<br/>alias: 'o'<br/>joinType: ROOT<br/>children: ∅</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">帧 ③ — <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.select(\"o.customer.name\").select(\"SUM(o.totalAmount)\")</code></h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">两个 SELECT 表达式注册到 SelectManager。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-3 select() ×2 后 — SelectManager 两个条目</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SelectManager<br/>items: 2</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SelectItem #0<br/>PathExpression</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">'o'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">'customer'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">'name'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SelectItem #1<br/>FunctionExpression</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">function: SUM</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">args[0]: PathExpression</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">'o'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">'totalAmount'</p></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">此时中间 JPQL：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// cb = cbf.create(em, Tuple.class).from(Order.class, \"o\")</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     .select(\"o.customer.name\").select(\"SUM(o.totalAmount)\");</span><br/>System.out.println(cb.getQueryString());<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 输出:</span><br/>SELECT o.customer.name, SUM(o.totalAmount)<br/>FROM Order o</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">帧 ④ — <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.join(\"o.items\", \"i\", JoinType.LEFT)</code></h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">JoinManager 在根节点下新增子节点——显式 LEFT JOIN。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-4 join() 后 — JoinNode 树新增子节点</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JoinNode<br/>type: Order<br/>alias: 'o'<br/>joinType: ROOT</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JoinNode<br/>attribute: items<br/>alias: 'i'<br/>joinType: LEFT<br/>explicit: true</p></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 加入 .join(\"o.items\", \"i\", JoinType.LEFT) 后:</span><br/>System.out.println(cb.getQueryString());<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 输出:</span><br/>SELECT o.customer.name, SUM(o.totalAmount)<br/>FROM Order o<br/>LEFT JOIN o.items i</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">帧 ⑤ — <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.where(\"o.status\").eq(OrderStatus.COMPLETED)</code></h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">WhereManager 创建第一个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EqPredicate</code>，放入根 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CompoundPredicate(AND)</code>。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-5 where().eq() 后 — WhereManager 第一个谓词</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">WhereManager</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CompoundPredicate<br/>operator: AND</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EqPredicate</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PathExpression<br/>o → status</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ParameterExpression<br/>:param_0<br/>value: COMPLETED</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">帧 ⑥ — <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.where(\"i.product.category\").eq(\"Electronics\")</code></h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">WhereManager 的 CompoundPredicate(AND) 新增第二个子谓词。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-6 两个 where() 后 — CompoundPredicate 含两个子谓词</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CompoundPredicate<br/>operator: AND</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EqPredicate #1</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PathExpr<br/>o → status</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Param :param_0<br/>COMPLETED</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EqPredicate #2</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PathExpr<br/>i → product → category</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Param :param_1<br/>'Electronics'</p></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 加入两个 where() 后:</span><br/>System.out.println(cb.getQueryString());<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 输出:</span><br/>SELECT o.customer.name, SUM(o.totalAmount)<br/>FROM Order o<br/>LEFT JOIN o.items i<br/>WHERE o.status = :param_0<br/>  AND i.product.category = :param_1</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">帧 ⑦ — <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.groupBy() / .having() / .orderByAsc() / .setMaxResults()</code></h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">三个 Manager 同时填充。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-7 groupBy + having + orderBy 后 — 三个 Manager 状态</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">GroupByManager</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">PathExpression<br/>o → customer → name</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">HavingManager</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">CompoundPredicate(AND)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">GtPredicate</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">FunctionExpr<br/>SUM(o.totalAmount)</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Param :param_2<br/>value: 1000</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">OrderByManager</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">OrderByItem<br/>ascending: true</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">PathExpression<br/>o → customer → name</p></section></td></tr></table></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 全部 API 调用完成后的完整 JPQL:</span><br/>System.out.println(cb.getQueryString());<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 输出:</span><br/>SELECT o.customer.name, SUM(o.totalAmount)<br/>FROM Order o<br/>LEFT JOIN o.items i<br/>WHERE o.status = :param_0<br/>  AND i.product.category = :param_1<br/>GROUP BY o.customer.name<br/>HAVING SUM(o.totalAmount) &gt; :param_2<br/>ORDER BY o.customer.name ASC</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">注意</strong> — 以上 JPQL 中 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">o.customer.name</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">i.product.category</code> 仍然使用用户书写的<strong style=\"color:#1a1a2e;font-weight:700;\">路径表达式形式</strong>。在后续的隐式 JOIN 解析阶段，这些路径将被分解为显式 JOIN + 别名引用。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">帧 ⑧ — 完整内部状态总览</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-8 全部 API 调用完成后 — Manager 完整状态</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\nAbstractCommonQueryBuilder · resultType: Tuple · maxResults: 20\n</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n📋 SelectManager\n#0 PathExpr<br/>o.customer.name<br/><br/>#1 FuncExpr<br/>SUM(o.totalAmount)\n\n\n🌳 JoinManager\nRoot: Order 'o'<br/>└─ LEFT: items 'i'\n\n\n🔍 WhereManager\nAND<br/>├─ o.status = :p0<br/>└─ i.product.category = :p1\n\n\n📊 GroupByManager\no.customer.name\n\n\n⚖️ HavingManager\nAND<br/>└─ SUM(o.totalAmount) > :p2\n\n\n🔢 OrderByManager\no.customer.name ASC\n\n</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">19.2 第二步：ExpressionFactory 解析字符串表达式</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">19.1 中调用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">select(\"o.customer.name\")</code> 时，字符串并不是直接存储——它会经过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ExpressionFactory</code> 的完整解析管线。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">路径表达式解析</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-9 ExpressionFactory 解析 \"o.customer.name\" 的完整管线</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">o</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">customer</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Lexer<br/>词法分析</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Token: ID 'o'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Token: DOT '.'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Token: ID 'customer'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Token: DOT '.'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Token: ID 'name'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Parser<br/>语法分析</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">PathExpression<br/>✅ 类型化节点</p></section></td></tr></table></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">解析后的数据结构（等价伪代码）：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// \"o.customer.name\" 被解析为:</span><br/>PathExpression {<br/>    base: JoinAliasExpression(\"o\"),   <span style=\"color:#6c7086;font-style:italic;\">// 指向 JoinManager 中 alias='o' 的 JoinNode</span><br/>    fields: [\"customer\", \"name\"],     <span style=\"color:#6c7086;font-style:italic;\">// 路径段列表</span><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 元数据 (类型解析后填充):</span><br/>    <span style=\"color:#6c7086;font-style:italic;\">//   field[0]: Order.customer -&gt; @ManyToOne Customer</span><br/>    <span style=\"color:#6c7086;font-style:italic;\">//   field[1]: Customer.name  -&gt; String (标量终端)</span><br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 关键: \"customer\" 是关联属性 → 隐式 JOIN 候选</span><br/><span style=\"color:#6c7086;font-style:italic;\">//        \"name\" 是标量属性     → 路径终端，映射到列</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">聚合函数表达式解析</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-10 ExpressionFactory 解析 \"SUM(o.totalAmount)\" 的管线</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">o</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">totalAmount</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Lexer</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Token: FUNC 'SUM'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Token: LPAREN</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Token: ID 'o'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Token: DOT</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Token: ID 'totalAmount'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Token: RPAREN</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Parser</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">FunctionExpression<br/>function: SUM</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">args[0]:<br/>PathExpression<br/>o.totalAmount</p></section></td></tr></table></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// \"SUM(o.totalAmount)\" 被解析为:</span><br/>FunctionExpression {<br/>    functionName: \"SUM\",<br/>    args: [<br/>        PathExpression {<br/>            base: JoinAliasExpression(\"o\"),<br/>            fields: [\"totalAmount\"],<br/>            <span style=\"color:#6c7086;font-style:italic;\">// totalAmount 是 Order 的标量属性 → 无需隐式 JOIN</span><br/>        }<br/>    ]<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 对比: 如果写 \"SUM(o.items.price)\"</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   → args[0].fields = [\"items\", \"price\"]</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   → \"items\" 是集合关联 → 需要隐式 JOIN</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">WHERE 子句的谓词表达式解析</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// where(\"o.status\").eq(OrderStatus.COMPLETED) 解析为:</span><br/>EqPredicate {<br/>    left:  PathExpression { base: \"o\", fields: [\"status\"] },<br/>    right: ParameterExpression { name: \"param_0\", value: OrderStatus.COMPLETED }<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// where(\"i.product.category\").eq(\"Electronics\") 解析为:</span><br/>EqPredicate {<br/>    left:  PathExpression { base: \"i\", fields: [\"product\", \"category\"] },<br/>    <span style=\"color:#6c7086;font-style:italic;\">//                                          ^^^^^^^^ 关联属性 → 隐式 JOIN 候选</span><br/>    right: ParameterExpression { name: \"param_1\", value: \"Electronics\" }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">表达式类型体系</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-11 本查询涉及的 Expression 类型层次</p><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">Expression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;interface&gt;&gt; · accept</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">PathExpression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">base · fields</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">FunctionExpression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">functionName · args</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">ParameterExpression</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">name · value</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">CompoundPredicate</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">operator · children</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">EqPredicate</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">left · right</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">GtPredicate</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">left · right</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">19.3 第三步：隐式 JOIN 解析</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">路径表达式 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">o.customer.name</code> 隐含了一次关联遍历：<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Order → Customer</code>。而 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">i.product.category</code> 隐含了 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Item → Product</code>。Blaze-Persistence 会在查询构建阶段自动检测并生成隐式 JOIN。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">隐式 JOIN 推导过程</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-12 路径表达式触发隐式 JOIN 推导</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">o</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">customer</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Order</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Customer</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">name</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">i</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">product</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">OrderItem</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Product</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">category</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PathExpression<br/>'o.customer.name'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">扫描路径段</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">'o' → 根别名<br/>解析为 Order</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">'customer' → 关联属性<br/>Order.customer → Customer<br/>⚠️ 需要 JOIN</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">'name' → 标量属性<br/>Customer.name → String<br/>✅ 终端</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PathExpression<br/>'i.product.category'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">扫描路径段</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">'i' → 别名<br/>解析为 OrderItem</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">'product' → 关联属性<br/>OrderItem.product → Product<br/>⚠️ 需要 JOIN</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">'category' → 标量属性<br/>Product.category → String<br/>✅ 终端</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">JoinNode 树变化：解析前 vs 解析后</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-13 JoinNode 树 — 隐式 JOIN 解析前 (仅用户显式声明)</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JoinNode<br/>Order 'o'<br/>type: ROOT</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JoinNode<br/>items 'i'<br/>type: LEFT<br/>explicit: ✅</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-14 JoinNode 树 — 隐式 JOIN 解析后 (自动扩展)</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JoinNode<br/>Order 'o'<br/>type: ROOT</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JoinNode<br/>items 'i'<br/>type: LEFT<br/>explicit: ✅</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JoinNode<br/>customer 'customer_1'<br/>type: INNER<br/>implicit: ✅</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JoinNode<br/>product 'product_1'<br/>type: INNER<br/>implicit: ✅</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">JPQL 对比：隐式 JOIN 解析前 vs 解析后</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">这是隐式 JOIN 解析最核心的变化——对比用户视角的\"简写 JPQL\"和框架生成的\"展开 JPQL\"：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- ═══════════════════════════════════════════════════<br/>-- BEFORE: 隐式 JOIN 解析前 (用户视角的路径表达式)<br/>-- ═══════════════════════════════════════════════════<br/>SELECT o.customer.name, SUM(o.totalAmount)<br/>FROM Order o<br/>LEFT JOIN o.items i<br/>WHERE o.status = :param_0<br/>  AND i.product.category = :param_1<br/>GROUP BY o.customer.name<br/>HAVING SUM(o.totalAmount) &gt; :param_2<br/>ORDER BY o.customer.name ASC<br/><br/>-- ═══════════════════════════════════════════════════<br/>-- AFTER: 隐式 JOIN 解析后 (实际生成的 JPQL)<br/>-- ═══════════════════════════════════════════════════<br/>SELECT customer_1.name, SUM(o.totalAmount)<br/>FROM Order o<br/>LEFT JOIN o.items i<br/>JOIN o.customer customer_1        -- 隐式 INNER JOIN<br/>JOIN i.product product_1          -- 隐式 INNER JOIN<br/>WHERE o.status = :param_0<br/>  AND product_1.category = :param_1   -- 路径重写: i.product.category → product_1.category<br/>GROUP BY customer_1.name               -- 路径重写: o.customer.name → customer_1.name<br/>HAVING SUM(o.totalAmount) &gt; :param_2<br/>ORDER BY customer_1.name ASC           -- 路径重写: o.customer.name → customer_1.name</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">三个关键变化</strong> — ① <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">o.customer.name</code> → <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">customer_1.name</code>（路径重写），② 自动插入 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JOIN o.customer customer_1</code>（隐式 JOIN 生成），③ <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">i.product.category</code> → <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">product_1.category</code>（路径重写 + 隐式 JOIN <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JOIN i.product product_1</code>）。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">JOIN 去重机制</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-15 JOIN 去重 — 多路径引用同一关联</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">引用来源</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">SELECT customer_1.name</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">GROUP BY customer_1.name</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">ORDER BY customer_1.name</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">JoinManager</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">customer<br/>已存在?</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">创建 JoinNode<br/>customer_1</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">复用已有<br/>customer_1</p></section></td></tr></table></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 去重验证: 三处引用 o.customer，只生成一个 JOIN</span><br/><span style=\"color:#6c7086;font-style:italic;\">// JoinManager 内部使用 (parentNode, attributeName) 作为唯一 key:</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 第一次遇到 o.customer (来自 SELECT):</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   key = (rootNode_o, \"customer\") → 不存在 → 创建 JoinNode(\"customer_1\")</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 第二次遇到 o.customer (来自 GROUP BY):</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   key = (rootNode_o, \"customer\") → 已存在 → 复用 customer_1</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 第三次遇到 o.customer (来自 ORDER BY):</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   key = (rootNode_o, \"customer\") → 已存在 → 复用 customer_1</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 最终 JPQL 中只有一条: JOIN o.customer customer_1</span></p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">19.4 第四步：QueryGenerator JPQL 生成</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">调用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">cb.getQueryString()</code>（或内部触发查询执行）时，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">QueryGenerator</code> 遍历所有 Manager，按固定顺序拼接 JPQL 字符串。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">QueryGenerator 遍历顺序</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-16 QueryGenerator 按序访问各 Manager</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">QueryGenerator</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">SelectManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">JoinManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">WhereManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">GroupByManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">HavingManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">OrderByManager</th></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">JPQL 字符串逐子句生长</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">每访问一个 Manager，StringBuilder 追加对应片段。以下展示每一步 StringBuilder 的内容：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ── QueryGenerator 内部 StringBuilder 逐步追踪 ──</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ① visitSelect(SelectManager):</span><br/>sb = \"SELECT customer_1.name, SUM(o.totalAmount)\"<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ② visitFrom(JoinManager):</span><br/>sb += \" FROM Order o\"<br/><span style=\"color:#6c7086;font-style:italic;\">// → \"SELECT customer_1.name, SUM(o.totalAmount) FROM Order o\"</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ③ visitJoins(JoinManager):</span><br/>sb += \" LEFT JOIN o.items i\"<br/>sb += \" JOIN o.customer customer_1\"<br/>sb += \" JOIN i.product product_1\"<br/><span style=\"color:#6c7086;font-style:italic;\">// → \"... FROM Order o LEFT JOIN o.items i JOIN o.customer customer_1 JOIN i.product product_1\"</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ④ visitWhere(WhereManager):</span><br/>sb += \" WHERE o.status = :param_0 AND product_1.category = :param_1\"<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ⑤ visitGroupBy(GroupByManager):</span><br/>sb += \" GROUP BY customer_1.name\"<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ⑥ visitHaving(HavingManager):</span><br/>sb += \" HAVING SUM(o.totalAmount) &gt; :param_2\"<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ⑦ visitOrderBy(OrderByManager):</span><br/>sb += \" ORDER BY customer_1.name ASC\"</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Expression Visitor 模式 — WHERE 子句遍历详解</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-17 Visitor 模式遍历 WHERE 子句表达式树</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">o</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">status</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">product_1</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">category</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">QueryGenerator<br/>(Visitor)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">visit(CompoundPredicate AND)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">visit(EqPredicate #1)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">visit(PathExpr o.status)<br/>→ 'o.status'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">visit(ParamExpr :param_0)<br/>→ ':param_0'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">拼接 '='<br/>→ 'o.status = :param_0'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">visit(EqPredicate #2)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">visit(PathExpr product_1.category)<br/>→ 'product_1.category'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">visit(ParamExpr :param_1)<br/>→ ':param_1'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">拼接 '='<br/>→ 'product_1.category = :param_1'</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">拼接 ' AND '<br/>→ 完整 WHERE</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">最终生成的完整 JPQL</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- ═══════════════════════════════════════════════════<br/>-- QueryGenerator 最终输出的 JPQL (cb.getQueryString())<br/>-- ═══════════════════════════════════════════════════<br/><br/>SELECT customer_1.name, SUM(o.totalAmount)<br/>FROM Order o<br/>LEFT JOIN o.items i<br/>JOIN o.customer customer_1<br/>JOIN i.product product_1<br/>WHERE o.status = :param_0<br/>  AND product_1.category = :param_1<br/>GROUP BY customer_1.name<br/>HAVING SUM(o.totalAmount) &gt; :param_2<br/>ORDER BY customer_1.name ASC</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e6a81744;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">调试技巧</strong> — 在任何时刻调用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">cb.getQueryString()</code> 即可看到当前的 JPQL，无需执行查询。这对于排查生成的 JPQL 是否符合预期非常有用。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">19.5 第五步：JPA Provider (Hibernate) HQL → SQL</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 的输出是标准 JPQL 字符串。它被交给 JPA Provider（这里以 Hibernate 5/6 为例）进行后续处理。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Hibernate 内部管线</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-18 JPQL → Hibernate 内部 → 原生 SQL 完整管线</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Blaze-Persistence</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">HQL Parser</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Semantic[BR]Analyzer</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Hibernate[BR]AST</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">SQL[BR]Generator</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Database</th></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">实体映射 → 表/列名转换</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-19 Hibernate 实体映射转换明细</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">JPQL</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Order</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Customer</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">OrderItem</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Product</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">o.status</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">o.totalAmount</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">customer_1.name</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">product_1.category</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">SQL</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">orders</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">customers</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">order_items</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">products</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">o0_.status</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">o0_.total_amount</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">c1_.name</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">p1_.category</p></section></td></tr></table></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">映射转换详细对应表：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- ═══════════════════════════════════════════════════<br/>-- Hibernate 实体/属性 → SQL 表/列 映射<br/>-- ═══════════════════════════════════════════════════<br/><br/>-- 实体 → 表:<br/>--   Order       →  orders          (@Table(name=\"orders\"))<br/>--   Customer    →  customers       (@Table(name=\"customers\"))<br/>--   OrderItem   →  order_items     (@Table(name=\"order_items\"))<br/>--   Product     →  products        (@Table(name=\"products\"))<br/><br/>-- 属性 → 列:<br/>--   Order.status        →  orders.status<br/>--   Order.totalAmount   →  orders.total_amount   (@Column(name=\"total_amount\"))<br/>--   Customer.name       →  customers.name<br/>--   Product.category    →  products.category<br/><br/>-- JOIN 关联 → 外键条件:<br/>--   LEFT JOIN o.items i          →  LEFT OUTER JOIN order_items i1_ ON o0_.id = i1_.order_id<br/>--   JOIN o.customer customer_1   →  INNER JOIN customers c1_ ON o0_.customer_id = c1_.id<br/>--   JOIN i.product product_1     →  INNER JOIN products p1_ ON i1_.product_id = p1_.id</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">最终原生 SQL — PostgreSQL 方言</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- ═══════════════════════════════════════════════════<br/>-- Hibernate 生成的最终原生 SQL (PostgreSQL 方言)<br/>-- 通过 hibernate.show_sql=true 或 logging 可捕获<br/>-- ═══════════════════════════════════════════════════<br/><br/>SELECT<br/>    c1_.name            AS col_0_0_,<br/>    SUM(o0_.total_amount) AS col_1_0_<br/>FROM<br/>    orders o0_<br/>    LEFT OUTER JOIN order_items i1_<br/>        ON o0_.id = i1_.order_id<br/>    INNER JOIN customers c1_<br/>        ON o0_.customer_id = c1_.id<br/>    INNER JOIN products p1_<br/>        ON i1_.product_id = p1_.id<br/>WHERE<br/>    o0_.status = ?<br/>    AND p1_.category = ?<br/>GROUP BY<br/>    c1_.name<br/>HAVING<br/>    SUM(o0_.total_amount) &gt; ?<br/>ORDER BY<br/>    c1_.name ASC<br/>LIMIT ?</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">方言差异</strong> — <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LIMIT ?</code> 是 PostgreSQL 方言的分页语法。如果使用 MySQL 方言，输出相同；如果使用 Oracle 方言，则使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">FETCH FIRST ? ROWS ONLY</code>（12c+）或 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ROWNUM</code> 嵌套。SQL Server 使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">TOP(?) ... ORDER BY</code> 或 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OFFSET 0 ROWS FETCH NEXT ? ROWS ONLY</code>。\n</section>\n<section><h4 style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">MySQL 方言输出对比</h4></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- MySQL 方言 (与 PostgreSQL 基本一致，仅别名风格可能不同):<br/>SELECT<br/>    c1_.name            AS col_0_0_,<br/>    SUM(o0_.total_amount) AS col_1_0_<br/>FROM<br/>    orders o0_<br/>    LEFT OUTER JOIN order_items i1_<br/>        ON o0_.id = i1_.order_id<br/>    INNER JOIN customers c1_<br/>        ON o0_.customer_id = c1_.id<br/>    INNER JOIN products p1_<br/>        ON i1_.product_id = p1_.id<br/>WHERE<br/>    o0_.status = ?<br/>    AND p1_.category = ?<br/>GROUP BY<br/>    c1_.name<br/>HAVING<br/>    SUM(o0_.total_amount) &gt; ?<br/>ORDER BY<br/>    c1_.name ASC<br/>LIMIT ?</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">参数绑定：JPQL 命名参数 → JDBC 位置参数</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-20 参数绑定：JPQL 命名参数 → JDBC 位置参数</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">JPQL</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">:param_0<br/>OrderStatus.COMPLETED</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">:param_1<br/>'Electronics'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">:param_2<br/>1000</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">JDBC</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">? (index=1)<br/>→ 'COMPLETED'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">? (index=2)<br/>→ 'Electronics'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">? (index=3)<br/>→ 1000</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">? (index=4)<br/>→ 20 (maxResults)</p></section></td></tr></table></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Hibernate<br/>ParameterBinder</p></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- JDBC PreparedStatement 参数绑定日志<br/>-- (通过 Hibernate logging: org.hibernate.type.descriptor.sql.BasicBinder=TRACE)<br/><br/>binding parameter [1] as [VARCHAR] - [COMPLETED]<br/>binding parameter [2] as [VARCHAR] - [Electronics]<br/>binding parameter [3] as [BIGINT]  - [1000]<br/>binding parameter [4] as [INTEGER] - [20]</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">开启 SQL 日志的配置</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\"># application.properties (Spring Boot / Quarkus 通用)</span><br/><span style=\"color:#6c7086;font-style:italic;\"># 显示 Blaze-Persistence 生成的 JPQL:</span><br/>logging.level.com.blazebit.persistence.impl=DEBUG<br/><br/><span style=\"color:#6c7086;font-style:italic;\"># 显示 Hibernate 生成的 SQL:</span><br/>spring.jpa.show-sql=true<br/>spring.jpa.properties.hibernate.format_sql=true<br/><br/><span style=\"color:#6c7086;font-style:italic;\"># 显示绑定的参数值:</span><br/>logging.level.org.hibernate.type.descriptor.sql.BasicBinder=TRACE<br/><br/><span style=\"color:#6c7086;font-style:italic;\"># 或 persistence.xml 中:</span><br/><span style=\"color:#6c7086;font-style:italic;\"># &lt;property name=\"hibernate.show_sql\" value=\"true\"/&gt;</span><br/><span style=\"color:#6c7086;font-style:italic;\"># &lt;property name=\"hibernate.format_sql\" value=\"true\"/&gt;</span></p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">19.6 第六步：结果集映射</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">SQL 执行后，JDBC <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ResultSet</code> 返回原始行列数据，需要映射为 Java 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Tuple</code> 对象。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-21 ResultSet → Tuple 映射序列</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Database</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">ResultSet</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">TupleTransformer</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">List&lt;Tuple&gt;</th></tr></table></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 获取结果并遍历:</span><br/>List&lt;Tuple&gt; results = cb.getResultList();<br/><br/>for (Tuple t : results) {<br/>    String customerName = t.get(0, String.class);        <span style=\"color:#6c7086;font-style:italic;\">// col_0_0_ → customer name</span><br/>    BigDecimal totalAmount = t.get(1, BigDecimal.class);  <span style=\"color:#6c7086;font-style:italic;\">// col_1_0_ → SUM(total_amount)</span><br/>    System.out.println(customerName + \": \" + totalAmount);<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 控制台输出 (示例数据):</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 张三: 15000.00</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 李四: 12500.00</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 王五: 8800.50</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 赵六: 5200.00</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 陈七: 3100.75</span><br/><span style=\"color:#6c7086;font-style:italic;\">// ...最多 20 行</span></p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Tuple 对象的内部结构：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Tuple 内部实质上是一个 Object[] 数组:</span><br/><span style=\"color:#6c7086;font-style:italic;\">// Tuple {</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   elements: [\"张三\", BigDecimal(\"15000.00\")]</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   aliases:  [\"col_0_0_\", \"col_1_0_\"]</span><br/><span style=\"color:#6c7086;font-style:italic;\">// }</span><br/><span style=\"color:#6c7086;font-style:italic;\">//</span><br/><span style=\"color:#6c7086;font-style:italic;\">// t.get(0) → elements[0] → \"张三\"</span><br/><span style=\"color:#6c7086;font-style:italic;\">// t.get(1) → elements[1] → BigDecimal(\"15000.00\")</span><br/><span style=\"color:#6c7086;font-style:italic;\">//</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 也可以通过 SELECT 别名访问 (如果设置了):</span><br/><span style=\"color:#6c7086;font-style:italic;\">// cb.select(\"o.customer.name\", \"customerName\");</span><br/><span style=\"color:#6c7086;font-style:italic;\">// → t.get(\"customerName\") 即可</span></p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">19.7 完整管线一图总览</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">将以上六步合为一张全景图。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-22 Java 代码到 SQL 全路径 — 完整管线</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n① Java API 调用\nCriteriaBuilder<br/>链式 API 调用<br/>↓<br/>Manager 群填充\n\n→\n\n② ExpressionFactory\n字符串表达式<br/>↓<br/>类型化表达式树\n\n→\n\n③ 隐式 JOIN\n路径遍历<br/>检测关联属性<br/>↓<br/>JoinNode 树扩展\n\n→\n\n④ QueryGenerator\nVisitor 遍历<br/>所有 Manager<br/>↓<br/>JPQL 字符串\n\n→\n\n⑤ Hibernate\nHQL Parser<br/>语义分析<br/>↓<br/>原生 SQL\n\n→\n\n⑥ 执行 & 映射\nJDBC 执行<br/>PreparedStatement<br/>↓<br/>List<Tuple> / List<View>\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">数据形态变换全览</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-23 数据形态变换全览 — 每一步的输入与输出</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Java 方法调用<br/>.select() .where()</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">select</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Manager 内部状态<br/>表达式对象图</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">隐式 JOIN<br/>扩展后的 JoinNode 树</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">JPQL 字符串<br/>面向对象查询</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Hibernate AST<br/>语义化语法树</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">SQL 字符串<br/>面向表的查询</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">ResultSet<br/>行列数据</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Tuple / View<br/>Java 对象</p></section></td></tr></table></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">从 Java 到数据库再回到 Java 的完整数据变换链，每一步的输出格式汇总：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ══════════════════════════════════════════════════════════════</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 全路径数据形态变换 — 从 Java 到 SQL 再回 Java</span><br/><span style=\"color:#6c7086;font-style:italic;\">// ══════════════════════════════════════════════════════════════</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ① Java 方法调用:</span><br/>cb.select(\"o.customer.name\")<br/><span style=\"color:#6c7086;font-style:italic;\">//   → 字符串 \"o.customer.name\"</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ② ExpressionFactory:</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   → PathExpression { base=\"o\", fields=[\"customer\",\"name\"] }</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ③ 隐式 JOIN 解析:</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   → JoinNode(customer_1) 插入</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   → PathExpression 重写为 { base=\"customer_1\", fields=[\"name\"] }</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ④ QueryGenerator (JPQL):</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   → \"SELECT customer_1.name, SUM(o.totalAmount)</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      FROM Order o LEFT JOIN o.items i</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      JOIN o.customer customer_1 JOIN i.product product_1</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      WHERE o.status = :param_0 AND product_1.category = :param_1</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      GROUP BY customer_1.name HAVING SUM(o.totalAmount) &gt; :param_2</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      ORDER BY customer_1.name ASC\"</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ⑤ Hibernate SQL:</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   → \"SELECT c1_.name, SUM(o0_.total_amount)</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      FROM orders o0_</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      LEFT OUTER JOIN order_items i1_ ON o0_.id = i1_.order_id</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      INNER JOIN customers c1_ ON o0_.customer_id = c1_.id</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      INNER JOIN products p1_ ON i1_.product_id = p1_.id</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      WHERE o0_.status = ? AND p1_.category = ?</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      GROUP BY c1_.name HAVING SUM(o0_.total_amount) &gt; ?</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      ORDER BY c1_.name ASC LIMIT ?\"</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ⑥ JDBC 执行 → ResultSet:</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   → row[0] = [\"张三\", 15000.00]</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   → row[1] = [\"李四\", 12500.00]</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   → ...</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ⑦ Tuple 映射:</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   → Tuple { elements: [\"张三\", BigDecimal(15000.00)] }</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   → Tuple { elements: [\"李四\", BigDecimal(12500.00)] }</span></p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">19.8 与 Entity View 的路径差异</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">当查询通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewSetting</code> 应用 Entity View 时，管线中的多个步骤发生变化。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Entity View 定义</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>public interface OrderSummaryView {<br/><br/>    @Mapping(\"customer.name\")<br/>    String getCustomerName();<br/><br/>    @Mapping(\"SUM(totalAmount)\")<br/>    BigDecimal getTotalAmount();<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">使用 Entity View 的查询代码</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 基础查询 (不含 SELECT — 由 Entity View 自动生成):</span><br/>CriteriaBuilder&lt;Order&gt; baseCb = cbf.create(em, Order.class, \"o\")<br/>    .join(\"o.items\", \"i\", JoinType.LEFT)<br/>    .where(\"o.status\").eq(OrderStatus.COMPLETED)<br/>    .where(\"i.product.category\").eq(\"Electronics\")<br/>    .groupBy(\"o.customer.name\")<br/>    .having(\"SUM(o.totalAmount)\").gt(1000)<br/>    .orderByAsc(\"o.customer.name\")<br/>    .setMaxResults(20);<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 应用 Entity View:</span><br/>EntityViewSetting&lt;OrderSummaryView, CriteriaBuilder&lt;OrderSummaryView&gt;&gt; setting =<br/>    EntityViewSetting.create(OrderSummaryView.class);<br/>CriteriaBuilder&lt;OrderSummaryView&gt; cb = evm.applySetting(setting, baseCb);<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 查看生成的 JPQL:</span><br/>System.out.println(cb.getQueryString());<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 输出 (与手写版本完全一致):</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SELECT customer_1.name, SUM(o.totalAmount)</span><br/><span style=\"color:#6c7086;font-style:italic;\">// FROM Order o</span><br/><span style=\"color:#6c7086;font-style:italic;\">// LEFT JOIN o.items i</span><br/><span style=\"color:#6c7086;font-style:italic;\">// JOIN o.customer customer_1</span><br/><span style=\"color:#6c7086;font-style:italic;\">// JOIN i.product product_1</span><br/><span style=\"color:#6c7086;font-style:italic;\">// WHERE o.status = :param_0</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   AND product_1.category = :param_1</span><br/><span style=\"color:#6c7086;font-style:italic;\">// GROUP BY customer_1.name</span><br/><span style=\"color:#6c7086;font-style:italic;\">// HAVING SUM(o.totalAmount) &gt; :param_2</span><br/><span style=\"color:#6c7086;font-style:italic;\">// ORDER BY customer_1.name ASC</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">JPQL 完全相同</strong> — Entity View 的 SELECT 子句从 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping</code> 注解推导而来，但最终生成的 JPQL 与手写 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.select()</code> 完全一致。<strong style=\"color:#1a1a2e;font-weight:700;\">差异仅在结果映射阶段。</strong>\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">无 View vs 有 View — SELECT 生成路径对比</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-24 SELECT 子句生成路径对比</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">WITHOUT</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">开发者手写<br/>.select('o.customer.name')<br/>.select('SUM(o.totalAmount)')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SelectManager<br/>手动填充的 SelectItem</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT customer_1.name,<br/>SUM(o.totalAmount)</p></section></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">WITH</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@Mapping 注解<br/>定义在 View 接口上</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewSetting.create()<br/>应用到 CriteriaBuilder</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SelectManager<br/>自动从 @Mapping 填充</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT customer_1.name,<br/>SUM(o.totalAmount)<br/>(自动生成，结果相同)</p></section></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">完整路径差异对比</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-25 完整管线对比 — Tuple 路径 vs Entity View 路径</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">TUPLE_PATH</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">手写 SELECT</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">QueryGenerator</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JPQL</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SQL</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ResultSet</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">TupleTransformer</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">List<Tuple></p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">VIEW_PATH</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewSetting<br/>应用</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">自动 SELECT<br/>from @Mapping</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">QueryGenerator</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JPQL</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SQL</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ResultSet</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ObjectBuilder</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">View Proxy 构造</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">List<View></p></section></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">CriteriaBuilder<br/>构建查询</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Entity View 结果映射 — ObjectBuilder 代理创建</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 19-26 ObjectBuilder 从 ResultSet 构建 View 代理</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">ResultSet</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">ObjectBuilder</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">View Proxy[BR](生成类)</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">List&lt;View&gt;</th></tr></table></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Entity View 结果获取:</span><br/>List&lt;OrderSummaryView&gt; results = cb.getResultList();<br/><br/>for (OrderSummaryView view : results) {<br/>    <span style=\"color:#6c7086;font-style:italic;\">// 类型安全的 getter — 不再需要 t.get(0, String.class)</span><br/>    String name = view.getCustomerName();<br/>    BigDecimal total = view.getTotalAmount();<br/>    System.out.println(name + \": \" + total);<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 控制台输出 (与 Tuple 版本结果相同):</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 张三: 15000.00</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 李四: 12500.00</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 王五: 8800.50</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ── 内部代理类 (编译时生成) ──</span><br/><span style=\"color:#6c7086;font-style:italic;\">// Blaze-Persistence 在编译期或运行时生成实现类:</span><br/><span style=\"color:#6c7086;font-style:italic;\">// class OrderSummaryView_Impl implements OrderSummaryView {</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     private final String customerName;</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     private final BigDecimal totalAmount;</span><br/><span style=\"color:#6c7086;font-style:italic;\">//</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     OrderSummaryView_Impl(String customerName, BigDecimal totalAmount) {</span><br/><span style=\"color:#6c7086;font-style:italic;\">//         this.customerName = customerName;</span><br/><span style=\"color:#6c7086;font-style:italic;\">//         this.totalAmount = totalAmount;</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     }</span><br/><span style=\"color:#6c7086;font-style:italic;\">//</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     @Override public String getCustomerName() { return customerName; }</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     @Override public BigDecimal getTotalAmount() { return totalAmount; }</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     @Override public boolean equals(Object o) { /* 基于字段的比较 */ }</span><br/><span style=\"color:#6c7086;font-style:italic;\">//     @Override public int hashCode() { /* 基于字段的哈希 */ }</span><br/><span style=\"color:#6c7086;font-style:italic;\">// }</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">CriteriaBuilder 链式调用</strong>逐步填充 6 个内部 Manager，每步调用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">getQueryString()</code> 可实时查看中间 JPQL。</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">ExpressionFactory</strong> 将字符串经词法/语法分析后解析为类型化的表达式节点：<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">PathExpression</code> 表示路径遍历，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">FunctionExpression</code> 表示聚合函数。</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">隐式 JOIN 解析</strong>是核心变换步骤——<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">o.customer.name</code> 被拆解为显式 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JOIN o.customer customer_1</code> + <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">customer_1.name</code>，使用属性路径去重避免重复 JOIN。</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">QueryGenerator</strong> 以 Visitor 模式按固定顺序（SELECT → FROM → JOIN → WHERE → GROUP BY → HAVING → ORDER BY）遍历所有 Manager，将表达式树序列化为 JPQL 字符串。</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Hibernate</strong> 接收 JPQL 后经 HQL Parser → Semantic Analyzer → SQL Generator 翻译为原生 SQL：<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Order</code> → <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">orders</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">totalAmount</code> → <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">total_amount</code>、关联属性 JOIN → 外键 ON 条件。</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">结果映射</strong>在 Tuple 模式下通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">TupleTransformer</code> 完成（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">t.get(0)</code>）；在 Entity View 模式下通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ObjectBuilder</code> 构造代理对象（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">view.getCustomerName()</code>），提供类型安全的访问。</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Entity View 差异</strong>仅体现在 SELECT 自动生成（从 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping</code> 推导）和结果映射（ObjectBuilder → View Proxy）两步，生成的 JPQL 和 SQL 完全相同。</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">下一章 <span style=\"color:#1e6fff;\">第 20 章 · 扩展体系与框架自用机制</span> 将深入 Blaze-Persistence 的扩展点设计，了解如何为框架编写自定义扩展。</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">© 2026 图解 Blaze-Persistence · 第 19 章</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}